function updateLastUpdated(){const e=new Date;document.getElementById("last-updated").textContent=e.toLocaleDateString("en-US",{year:"numeric",month:"short",day:"numeric",hour:"2-digit",minute:"2-digit"})}function initTrafficChart(){const e=document.getElementById("trafficChart");e&&new Chart(e,{type:"line",data:{labels:["Jan 1","Jan 8","Jan 15","Jan 22","Jan 29","Feb 5"],datasets:[{label:"Page Views",data:[18500,22100,19800,24500,23200,26800],borderColor:"#7c3aed",backgroundColor:"rgba(124, 58, 237, 0.1)",fill:!0,tension:.4,pointRadius:4,pointHoverRadius:6},{label:"Unique Visitors",data:[2800,3400,3100,3800,3600,4200],borderColor:"#0d9488",backgroundColor:"rgba(13, 148, 136, 0.1)",fill:!0,tension:.4,pointRadius:4,pointHoverRadius:6}]},options:{responsive:!0,maintainAspectRatio:!1,plugins:{legend:{position:"top",align:"end",labels:{usePointStyle:!0,pointStyle:"circle",padding:20,font:{family:"Lato, sans-serif",size:12}}}},scales:{x:{grid:{display:!1},ticks:{font:{family:"Lato, sans-serif",size:11}}},y:{beginAtZero:!0,grid:{color:"rgba(0,0,0,0.05)"},ticks:{font:{family:"Lato, sans-serif",size:11}}}},interaction:{intersect:!1,mode:"index"}}})}function initTopPagesChart(){const e=document.getElementById("topPagesChart");e&&new Chart(e,{type:"bar",data:{labels:["Queen Amina","Mary Seacole","Hildegard of Bingen","Cleopatra","Yaa Asantewaa"],datasets:[{label:"Page Views",data:[12450,9820,8760,7650,6540],backgroundColor:["#7c3aed","#0d9488","#d97706","#7c3aed","#0d9488"],borderRadius:6,barThickness:32}]},options:{indexAxis:"y",responsive:!0,maintainAspectRatio:!1,plugins:{legend:{display:!1}},scales:{x:{beginAtZero:!0,grid:{color:"rgba(0,0,0,0.05)"},ticks:{font:{family:"Lato, sans-serif",size:11}}},y:{grid:{display:!1},ticks:{font:{family:"Playfair Display, serif",size:12}}}}}})}function initGeoChart(){const e=document.getElementById("geoChart");e&&new Chart(e,{type:"doughnut",data:{labels:["North America","Europe","Africa","Asia","South America","Oceania"],datasets:[{data:[32,24,18,14,8,4],backgroundColor:["#7c3aed","#0d9488","#d97706","#7c3aed80","#0d948880","#d9770680"],borderWidth:0,hoverOffset:8}]},options:{responsive:!0,maintainAspectRatio:!1,cutout:"65%",plugins:{legend:{position:"right",labels:{usePointStyle:!0,pointStyle:"circle",padding:16,font:{family:"Lato, sans-serif",size:12}}}}}})}function initCategoryChart(){const e=document.getElementById("categoryChart");e&&new Chart(e,{type:"radar",data:{labels:["Leadership","Science","Arts & Culture","Faith","Enterprise","Activism"],datasets:[{label:"Page Views",data:[85,72,68,55,78,62],borderColor:"#7c3aed",backgroundColor:"rgba(124, 58, 237, 0.2)",pointBackgroundColor:"#7c3aed",pointBorderColor:"#fff",pointHoverBackgroundColor:"#fff",pointHoverBorderColor:"#7c3aed",borderWidth:2},{label:"Avg. Time on Page",data:[75,82,65,70,68,72],borderColor:"#0d9488",backgroundColor:"rgba(13, 148, 136, 0.2)",pointBackgroundColor:"#0d9488",pointBorderColor:"#fff",pointHoverBackgroundColor:"#fff",pointHoverBorderColor:"#0d9488",borderWidth:2}]},options:{responsive:!0,maintainAspectRatio:!1,plugins:{legend:{position:"top",align:"end",labels:{usePointStyle:!0,pointStyle:"circle",padding:16,font:{family:"Lato, sans-serif",size:11}}}},scales:{r:{angleLines:{color:"rgba(0,0,0,0.1)"},grid:{color:"rgba(0,0,0,0.1)"},pointLabels:{font:{family:"Lato, sans-serif",size:11}},ticks:{display:!1}}}}})}function refreshData(){location.reload()}document.addEventListener("DOMContentLoaded",function(){initTrafficChart(),initTopPagesChart(),initGeoChart(),initCategoryChart(),updateLastUpdated()}),document.querySelector("button").addEventListener("click",function(){console.warn("Report export functionality would be implemented here with backend support.")}),document.querySelector("select").addEventListener("change",function(e){e.target.value});